B.G8=new A.b9(null,"Seis (6) imagens ser\xe3o apresentadas. Fique atendo! Em um certo momento do teste, elas ser\xe3o escondidas em uma figura e voc\xea dever\xe1 encontr\xe1-las.",!1,null,null,null)
B.G9=new A.b9(null,"Na pr\xf3xima tela ser\xe1 reproduzida uma lista de 10 pares de palavras relacionadas logicamente entre si (p. ex., alto-baixo). Depois, voc\xea ser\xe1 solicitado para preencher a palavra faltante. Fique atento, voc\xea ter\xe1 que memorizar todos os pares.\n\nQuando estiver pronto \xe9 s\xf3 clicar em pr\xf3ximo...",!1,null,null,null)
